def protocol_handlers(cls, protocol_version=None):
    """
    Devuelve un diccionario de los manejadores disponibles del protocolo Bolt, indexados por una tupla de versión. Si se proporciona una versión de protocolo explícita, el diccionario contendrá cero o un elemento, dependiendo de si esa versión es soportada. Si no se proporciona ninguna versión de protocolo, se devolverán todas las versiones disponibles.

    :param protocol_version: tupla que identifica una versión específica del protocolo 
        (por ejemplo, (3, 5)) o None
    :return: diccionario que mapea una tupla de versión a la clase del manejador para 
        todas las versiones relevantes y compatibles del protocolo
    :raise TypeError: si la versión del protocolo no se pasa como una tupla
    """
    if protocol_version is not None and not isinstance(protocol_version, tuple):
        raise TypeError("La versión del protocolo debe ser una tupla")

    # Suponiendo que hay un diccionario de manejadores de protocolo
    handlers = {
        (3, 5): "HandlerFor3_5",
        (4, 0): "HandlerFor4_0",
        (4, 1): "HandlerFor4_1",
    }

    if protocol_version is not None:
        return {protocol_version: handlers.get(protocol_version)} if protocol_version in handlers else {}

    return handlers

def values(self, *keys):
    """
    Devuelve los valores del registro, filtrando opcionalmente para incluir solo ciertos valores por índice o clave.

    :param keys: índices o claves de los elementos a incluir; si no se proporcionan, se incluirán todos los valores  
    :return: lista de valores  
    :rtype: list
    """
    if not keys:
        return list(self.data.values())
    return [self.data[key] for key in keys if key in self.data]

def data(self, *keys):
    """
    Devuelve las claves y valores de este registro como un diccionario, opcionalmente incluyendo solo ciertos valores por índice o clave. Las claves proporcionadas en los elementos que no están en el registro se insertarán con un valor de :const:`None`; los índices proporcionados que están fuera de los límites generarán una excepción :exc:`IndexError`.

    :param keys: índices o claves de los elementos a incluir; si no se proporciona ninguno, se incluirán todos los valores.
    :return: diccionario de valores, indexado por el nombre del campo.  
    :raises: :exc:`IndexError` si se especifica un índice fuera de los límites.  
    """
    if not keys:
        return {key: getattr(self, key, None) for key in self.__dict__}

    result = {}
    for key in keys:
        if isinstance(key, int):
            if key < 0 or key >= len(self):
                raise IndexError("Índice fuera de los límites.")
            result[key] = self[key]
        else:
            result[key] = getattr(self, key, None)

    return result

